+    pop(klass);
+    Register mark_word = t2;
+    if (UseCompactObjectHeaders || Arguments::is_valhalla_enabled()) {
+      ldr(mark_word, Address(klass, Klass::prototype_header_offset()));
+      str(mark_word, Address(new_obj, oopDesc::mark_offset_in_bytes()));
